import java.util.*;

public class UpperCase {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		String a = "gunavaty";
		String res = upper(a);
		System.out.println(res);

	}
	public static String upper(String str) {
		str.toUpperCase();
		return str.toUpperCase();
	}

}
